class Fenw:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (n + 1)

    def update(self, i, delta):
        idx = i + 1
        while idx <= self.n:
            self.tree[idx] += delta
            idx += (idx & -idx)

    def query_prefix(self, i):
        res = 0
        idx = i + 1
        while idx > 0:
            res += self.tree[idx]
            idx -= (idx & -idx)
        return res

    def query(self, l, r):
        if l > r:
            return 0
        if l == 0:
            return self.query_prefix(r)
        else:
            return self.query_prefix(r) - self.query_prefix(l - 1)

def solve(nums, queries):
    n = len(nums)
    depth_cache = {}
    def get_depth(x):
        if x == 1:
            return 0
        if x in depth_cache:
            return depth_cache[x]
        t = x
        steps = 0
        while t != 1:
            t = bin(t).count('1')
            steps += 1
        depth_cache[x] = steps
        return steps

    depth_arr = [get_depth(x) for x in nums]

    trees = [Fenw(n) for _ in range(6)]

    for i, d in enumerate(depth_arr):
        if d < 6:
            trees[d].update(i, 1)

    ans = []
    for q in queries:
        if q[0] == 1:
            l, r, k = q[1], q[2], q[3]
            if k < 6:
                res = trees[k].query(l, r)
            else:
                res = 0
            ans.append(res)
        else:
            idx, val = q[1], q[2]
            old_depth = depth_arr[idx]
            new_depth = get_depth(val)
            if old_depth < 6:
                trees[old_depth].update(idx, -1)
            if new_depth < 6:
                trees[new_depth].update(idx, 1)
            depth_arr[idx] = new_depth

    return ans
```

